/*
 * modf() test harness — prints (input_hex, frac_hex, int_hex) triples.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

#ifdef EN_PERF
static volatile double g_acc;

static void emit(double x)
{
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    double ipart;
    g_acc += modf(vx, &ipart);
    g_acc += ipart;
}
#else
static void emit(double x)
{
    double ipart;
    double fpart = modf(x, &ipart);
    printf("%016llx %016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(fpart), (unsigned long long)d2u(ipart));
}
#endif

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0);
    emit(-0.0);
    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    emit_u(0xfff8000000000000ULL);  /* -qNaN */
    emit_u(0x7ff0000000000000ULL);  /* +Inf */
    emit_u(0xfff0000000000000ULL);  /* -Inf */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x0000000000000001ULL);  /* min positive subnormal: 2^-1074 */
    emit_u(0x8000000000000001ULL);  /* min negative subnormal */
    emit_u(0x0008000000000000ULL);  /* mid positive subnormal */
    emit_u(0x8008000000000000ULL);  /* mid negative subnormal */
    emit_u(0x000fffffffffffffULL);  /* max positive subnormal: just below DBL_MIN */
    emit_u(0x800fffffffffffffULL);  /* max negative subnormal */

    /* --- Section 3: Normal boundary values (6) --- */
    emit(DBL_MIN);                              /* smallest positive normal: 2^-1022 */
    emit(-DBL_MIN);                             /* smallest negative normal */
    emit_u(0x0010000000000001ULL);              /* one ULP above DBL_MIN */
    emit(DBL_MAX);                              /* largest positive normal: 0x7fefffffffffffff */
    emit(-DBL_MAX);                             /* largest negative normal */
    emit_u(0x7fefffffffffffffULL - 1);          /* one ULP below DBL_MAX: 0x7feffffffffffffe */

    /* --- Section 4: Near 1.0 - ULP density region (8) --- */
    emit_u(0x3fefffffffffffffULL);  /* one ULP below 1.0 */
    emit(1.0);
    emit_u(0x3ff0000000000001ULL);  /* one ULP above 1.0 */
    emit_u(0x3feffffffffffffeULL);  /* a few ULPs below 1.0 */
    emit_u(0x3ff0000000000010ULL);  /* a few ULPs above 1.0 */
    emit(-1.0);
    emit_u(0xbfefffffffffffffULL);  /* one ULP toward zero from -1.0 */
    emit_u(0xbff0000000000001ULL);  /* one ULP away from zero from -1.0 */

    /* --- Section 5: Exponent switching points (6) --- */
    emit_u(0x3fe0000000000000ULL);  /* 0.5 exactly */
    emit_u(0x3fdffffffffffffULL);   /* one ULP below 0.5 */
    emit_u(0x3fe0000000000001ULL);  /* one ULP above 0.5 */
    emit_u(0x4000000000000000ULL);  /* 2.0 exactly */
    emit_u(0x3fffffffffffffffULL);  /* one ULP below 2.0 */
    emit_u(0x4000000000000001ULL);  /* one ULP above 2.0 */

    /* --- Section 6: Pure integers (12) --- */
    emit(-10.0);
    emit(-5.0);
    emit(-3.0);
    emit(-2.0);
    emit(-1.0);
    emit(1.0);   /* repeated but important as pure integer vs Section 4 ULP neighbor */
    emit(2.0);
    emit(3.0);
    emit(5.0);
    emit(10.0);
    emit(1.0e15);   /* large integer representable exactly as double */
    emit(-1.0e15);  /* large negative integer */

    /* --- Section 7: Near-integer and half-integer values (12) --- */
    emit(0.1);
    emit(0.25);
    emit(0.5);
    emit(0.75);
    emit(0.9);
    emit(1.5);
    emit(2.5);
    emit(-0.1);
    emit(-0.5);
    emit(-0.9);
    emit(-1.5);
    emit(-2.5);

    /* --- Section 8: Mixed fractional mid-range values (10) --- */
    emit(-5.9);
    emit(-5.1);
    emit(-3.7);
    emit(-2.2);
    emit(2.2);
    emit(3.7);
    emit(5.1);
    emit(5.9);
    emit(100.375);    /* large enough integer part, exact fraction */
    emit(-100.625);   /* negative counterpart */

    /* --- Section 9: Large values where fractional part vanishes (10) --- */
    emit(1.0e7);         /* above 2^23: float mantissa exhausted */
    emit(-1.0e7);
    emit(1.0e16);        /* above 2^53: double mantissa exhausted, all integer */
    emit(-1.0e16);
    emit(1.0e17);
    emit(-1.0e17);
    emit_u(0x4330000000000000ULL);  /* 2^52: exact double integer boundary */
    emit_u(0x4340000000000000ULL);  /* 2^53: all doubles >= this are integers */
    emit_u(0x4350000000000000ULL);  /* 2^54 */
    emit_u(0xc340000000000000ULL);  /* -2^53: negative integer boundary */

    /* --- Section 10: ULP neighbors of key power-of-2 transitions (23) --- */
    emit_u(0x3fc0000000000000ULL);  /* 0.125 = 2^-3 */
    emit_u(0x3fd0000000000000ULL);  /* 0.25 = 2^-2 */
    emit_u(0x3fe0000000000000ULL);  /* 0.5 = 2^-1 (dup of Sec5 but important) */
    emit_u(0x4000000000000000ULL);  /* 2.0 = 2^1 (dup of Sec5) */
    emit_u(0x4010000000000000ULL);  /* 4.0 = 2^2 */
    emit_u(0x400fffffffffffffULL);  /* one ULP below 4.0 */
    emit_u(0x4010000000000001ULL);  /* one ULP above 4.0 */
    emit_u(0x4020000000000000ULL);  /* 8.0 = 2^3 */
    emit_u(0x401fffffffffffffULL);  /* one ULP below 8.0 */
    emit_u(0x4024000000000000ULL);  /* 10.0 */
    emit_u(0x4059000000000000ULL);  /* 100.0 */
    emit_u(0x408f400000000000ULL);  /* 1000.0 */
    emit_u(0x4330000000000001ULL);  /* 2^52 + 1 ULP: fractional part just becomes representable */
    emit_u(0x432fffffffffffffULL);  /* one ULP below 2^52 */
    emit_u(0x433fffffffffffffULL);  /* one ULP below 2^53 */
    emit_u(0x4340000000000001ULL);  /* 2^53 + 1: integer, no fractional part */
    emit_u(0xc330000000000000ULL);  /* -2^52 */
    emit_u(0xc32fffffffffffffULL);  /* negative: one ULP below 2^52 magnitude */
    emit_u(0x3ff921fb54442d18ULL);  /* pi/2 ~ 1.5708: has both int and frac parts */
    emit_u(0x400921fb54442d18ULL);  /* pi ~ 3.1416 */
    emit_u(0x4012d97c7f3321d2ULL);  /* 3pi/2 ~ 4.7124 */
    emit_u(0x401921fb54442d18ULL);  /* 2pi ~ 6.2832 */
    emit_u(0x3fe62e42fefa39efULL);  /* ln2 ~ 0.6931: frac = ln2, int = 0 */
}

/* 9. Random sweep: 300 evenly spaced inputs */
#ifndef EN_PERF
static void test_random_300(void)
{
    double lo = -20.0;
    double hi =  20.0;
    int n = 300;
    for (int i = 0; i < n; i++) {
        double x = lo + (hi - lo) * (double)i / (double)(n - 1);
        emit(x);
    }
}
#endif

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf acc: %016llx\n", (unsigned long long)d2u((double)g_acc));
#else
    test_representative_100();
    test_random_300();
#endif
    return 0;
}

